// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract WhitelistRegistry {
    address public immutable owner;
    address public newOwner;
    mapping(address => bool) private whitelist;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event AddressAdded(address indexed addr);
    event AddressRemoved(address indexed addr);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier noReentrancy() {
        require(!locked, "No reentrancy");
        locked = true;
        _;
        locked = false;
    }

    bool private locked;

    function transferOwnership(address _newOwner) external onlyOwner {
        require(_newOwner != address(0), "New owner cannot be the zero address");
        newOwner = _newOwner;
        emit OwnershipTransferred(owner, _newOwner);
    }

    function acceptOwnership() external {
        require(msg.sender == newOwner, "Only the new owner can accept");
        address previousOwner = owner;
        owner = newOwner;
        delete newOwner;
        emit OwnershipTransferred(previousOwner, owner);
    }

    function addToWhitelist(address addr) external onlyOwner noReentrancy {
        if (!whitelist[addr]) {
            whitelist[addr] = true;
            emit AddressAdded(addr);
        }
    }

    function removeFromWhitelist(address addr) external onlyOwner noReentrancy {
        if (whitelist[addr]) {
            delete whitelist[addr];
            emit AddressRemoved(addr);
        }
    }

    function isWhitelisted(address addr) external view returns (bool) {
        return whitelist[addr];
    }
}
